import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"開発環境のセットアップ","description":"Fabric を使った Mod 開発環境をセットアップするための段階的なガイド。","frontmatter":{"title":"開発環境のセットアップ","description":"Fabric を使った Mod 開発環境をセットアップするための段階的なガイド。","authors":["2xsaiko","andrew6rant","asiekierka","daomephsta","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","telepathicgrunt"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"ja_jp/1.21.10/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.10/translated/ja_jp/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1766682904000}`);var o={name:`ja_jp/1.21.10/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">開発環境のセットアップ <a class="header-anchor" href="#h1" aria-label="Permalink to “開発環境のセットアップ”">​</a></h1><p>Fabric を使って Mod を開発するためには、IntelliJ IDEA を使用した開発環境を設定する必要があります。</p><h2 id="installing-jdk-21" tabindex="-1">JDK 21 のインストール <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “JDK 21 のインストール”">​</a></h2><p>Minecraft 1.21 を対象にした Mod を開発するには、JDK 21 が必要です。</p><p>Java のインストールでお困りの場合、<a href="./../../players/index">プレイヤーガイド</a> 内の Java インストールガイドをご覧になれます。</p><h2 id="installing-intellij-idea" tabindex="-1">IntelliJ IDEA のインストール <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “IntelliJ IDEA のインストール”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>このドキュメント内の多くの記事は IntelliJ IDEA の使用を前提として書かれています。Eclipse や Visual Studio Code などの別の IDE もお使いいただけますが、その場合は公式のドキュメントを確認するようにしてください。</p></div><p>まだ IntelliJ IDEA をインストールしていない場合は、<a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">公式ウェブサイト</a> からダウンロードできます。お使いの OS のインストールガイドに従ってください。</p><p>Community 版の IntelliJ IDEA は無料かつオープンソースであり、Fabric を使った Modding に推奨されています。</p><p>Community 版のダウンロードリンクを見つけるにはページをスクロールする必要があるかもしれません。リンクは以下のようになっています。</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="IDEA Community Edition Download Prompt" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">IDEA プラグインのインストール <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “IDEA プラグインのインストール”">​</a></h2><p>このプラグインは必須ではありませんが、Fabric での Modding を大幅に簡単にすることができるので、インストールを検討する価値があります。</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Minecraft Development プラグインは Fabric を使った Modding を支援します。これは最もインストールすべきプラグインです。</p><p>インストールするには、IntelliJ IDEA を開き、<code>ファイル（macOS の場合は、IntelliJ IDEA） &gt; 設定 &gt; プラグイン &gt; Marketplace タブ</code> を選択します。表示された検索バーで <code>Minecraft Development</code> を検索し、<code>インストール</code> ボタンをクリックしてください。</p><p>また、<a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">プラグインページ</a> からダウンロードして、<code>ファイル &gt; 設定 &gt; プラグイン &gt; ディスクからプラグインをインストール</code> からインストールすることもできます。</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};